DEFAULT_DB_PATH = os.environ.get("RAG_DB_PATH", "rag_store.sqlite3")
DEFAULT_DOCS_DIR = os.environ.get("RAG_DOCS_DIR", "docs")
DEFAULT_EMBED_MODEL = os.environ.get("RAG_EMBED_MODEL", "text-embedding-3-large")
DEFAULT_CHAT_MODEL = os.environ.get("RAG_CHAT_MODEL", "gpt-4.1-mini")
DEFAULT_TOP_K = int(os.environ.get("RAG_TOP_K", "8"))
DEFAULT_MAX_CHUNK_CHARS = int(os.environ.get("RAG_MAX_CHUNK_CHARS", "1800"))
DEFAULT_CHUNK_OVERLAP_CHARS = int(os.environ.get("RAG_CHUNK_OVERLAP_CHARS", "250"))
DEFAULT_MAX_CONTEXT_CHARS = int(os.environ.get("RAG_MAX_CONTEXT_CHARS", "120000"))
