DEFAULT_OPENAI_API_KEY = os.environ.get("OPENAI_API_KEY", "")


def _now_ts() -> int:
    return int(time.time())


def _sha256_hex(s: str) -> str:
    return hashlib.sha256(s.encode("utf-8")).hexdigest()


def _read_text_file(path: str) -> str:
    with open(path, "rb") as f:
        data = f.read()
    try:
        return data.decode("utf-8")
    except UnicodeDecodeError:
        try:
            return data.decode("utf-8", errors="replace")
        except Exception:
            return data.decode("latin-1", errors="replace")


def _iter_files(root: str) -> List[str]:
    patterns = [
        "**/*.txt",
        "**/*.md",
        "**/*.markdown",
        "**/*.rst",
        "**/*.json",
        "**/*.csv",
        "**/*.log",
        "**/*.yaml",
        "**/*.yml",
        "**/*.html",
        "**/*.htm",
        "**/*.xml",
    ]
    files = []
    for pat in patterns:
        files.extend(glob.glob(os.path.join(root, pat), recursive=True))
    files = [p for p in files if os.path.isfile(p)]
    files.sort()
    return files


def _normalize_whitespace(text: str) -> str:
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    lines = [ln.rstrip() for ln in text.split("\n")]
    out = "\n".join(lines)
    while "\n\n\n" in out:
        out = out.replace("\n\n\n", "\n\n")
    return out.strip()


def chunk_text(text: str, max_chars: int, overlap_chars: int) -> List[str]:
    text = _normalize_whitespace(text)
    if not text:
        return []
    if max_chars <= 0:
        return [text]
    if overlap_chars < 0:
        overlap_chars = 0
    chunks = []
    start = 0
    n = len(text)
    while start < n:
        end = min(start + max_chars, n)
        if end < n:
            window = text[start:end]
            cut = max(window.rfind("\n\n"), window.rfind("\n"), window.rfind(". "), window.rfind(" "))
            if cut != -1 and cut > max(0, int(0.6 * len(window))):
                end = start + cut + (2 if window[cut:cut+2] == ". " else 1)
        chunk = text[start:end].strip()
        if chunk:
            chunks.append(chunk)
        if end >= n:
            break
        start = max(0, end - overlap_chars)
        if start == end:
            start = end + 1
    return chunks


class OpenAIClient:
    def __init__(self, api_key: str, base_url: str = DEFAULT_OPENAI_BASE_URL, timeout: int = 120):
        self.api_key = api_key
        self.base_url = base_url.rstrip("/")
        self.timeout = timeout
        if not self.api_key:
            raise ValueError("OPENAI_API_KEY is required")

    def _headers(self) -> Dict[str, str]:
        return {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
        }

    def embeddings(self, model: str, inputs: List[str]) -> List[List[float]]:
        url = f"{self.base_url}/embeddings"
        payload = {"model": model, "input": inputs}
        r = requests.post(url, headers=self._headers(), json=payload, timeout=self.timeout)
        if r.status_code >= 400:
            raise RuntimeError(f"Embeddings error {r.status_code}: {r.text}")
        data = r.json()
        out = [None] * len(data["data"])
        for item in data["data"]:
            out[item["index"]] = item["embedding"]
        return out

    def chat(self, model: str, messages: List[Dict[str, str]], temperature: float = 0.2) -> str:
        url = f"{self.base_url}/chat/completions"
        payload = {"model": model, "messages": messages, "temperature": temperature}
        r = requests.post(url, headers=self._headers(), json=payload, timeout=self.timeout)
        if r.status_code >= 400:
            raise RuntimeError(f"Chat error {r.status_code}: {r.text}")
        data = r.json()
        return data["choices"][0]["message"]["content"]


class VectorStoreSQLite:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self._init_db()

    def _connect(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.execute("PRAGMA journal_mode=WAL;")
        conn.execute("PRAGMA synchronous=NORMAL;")
        return conn

    def _init_db(self) -> None:
        conn = self._connect()
        try:
            conn.execute(
                """
                CREATE TABLE IF NOT EXISTS documents (
                    id TEXT PRIMARY KEY,
                    source_path TEXT NOT NULL,
                    source_mtime INTEGER NOT NULL,
                    source_sha256 TEXT NOT NULL,
                    chunk_index INTEGER NOT NULL,
                    chunk_text TEXT NOT NULL,
                    metadata_json TEXT NOT NULL,
                    embedding BLOB NOT NULL,
                    embedding_dim INTEGER NOT NULL,
                    created_at INTEGER NOT NULL
                );
                """
            )
            conn.execute("CREATE INDEX IF NOT EXISTS idx_documents_source_path ON documents(source_path);")
            conn.execute("CREATE INDEX IF NOT EXISTS idx_documents_source_sha ON documents(source_sha256);")
            conn.commit()
        finally:
            conn.close()

    @staticmethod
    def _pack_embedding(vec: List[float]) -> Tuple[bytes, int]:
        arr = np.asarray(vec, dtype=np.float32)
        return arr.tobytes(), int(arr.shape[0])

    @staticmethod
    def _unpack_embedding(blob: bytes, dim: int) -> np.ndarray:
        arr = np.frombuffer(blob, dtype=np.float32)
        if dim and arr.shape[0] != dim:
            arr = arr[:dim]
        return arr

    def upsert_chunks(
        self,
        source_path: str,
        source_mtime: int,
        source_sha256: str,
        chunks: List[str],
        embeddings: List[List[float]],
        metadatas: Optional[List[Dict[str, Any]]] = None,
    ) -> int:
        if metadatas is None:
            metadatas = [{} for _ in chunks]
        if not (len(chunks) == len(embeddings) == len(metadatas)):
            raise ValueError("chunks, embeddings, metadatas length mismatch")

        conn = self._connect()
        try:
            conn.execute("DELETE FROM documents WHERE source_path = ?", (source_path,))
            created_at = _now_ts()
            rows = []
            for i, (ch, emb, md) in enumerate(zip(chunks, embeddings, metadatas)):
                doc_id = str(uuid.uuid4())
                blob, dim = self._pack_embedding(emb)
                md2 = dict(md or {})
                md2.update(
                    {
                        "source_path": source_path,
                        "chunk_index": i,
                        "source_mtime": source_mtime,
                        "source_sha256": source_sha256,
                    }
                )
                rows.append(
                    (
                        doc_id,
                        source_path,
                        int(source_mtime),
                        source_sha256,
                        int(i),
                        ch,
                        json.dumps(md2, ensure_ascii=False),
                        sqlite3.Binary(blob),
                        int(dim),
                        int(created_at),
                    )
                )
            conn.executemany(
                """
                INSERT INTO documents
                (id, source_path, source_mtime, source_sha256, chunk_index, chunk_text, metadata_json, embedding, embedding_dim, created_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                rows,
            )
            conn.commit()
            return len(rows)
        finally:
            conn.close()

    def list_sources(self) -> List[Dict[str, Any]]:
        conn = self._connect()
        try:
            cur = conn.execute(
                """
                SELECT source_path, MAX(source_mtime) as mtime, MAX(source_sha256) as sha, COUNT(*) as chunks
                FROM documents
                GROUP BY source_path
                ORDER BY source_path
                """
            )
            out = []
            for row in cur.fetchall():
                out.append({"source_path": row[0], "source_mtime": row[1], "source_sha256": row[2], "chunks": row[3]})
            return out
        finally:
            conn.close()

    def get_source_sha(self, source_path: str) -> Optional[str]:
        conn = self._connect()
        try:
            cur = conn.execute(
                "SELECT source_sha256 FROM documents WHERE source_path = ? LIMIT 1",
                (source_path,),
            )
            row = cur.fetchone()
            return row[0] if row else None
        finally:
            conn.close()

    def search(self, query_embedding: List[float], top_k: int = 8) -> List[Dict[str, Any]]:
        q = np.asarray(query_embedding, dtype=np.float32)
        qn = np.linalg.norm(q) + 1e-12
        conn = self._connect()
        try:
            cur = conn.execute(
                "SELECT id, source_path, chunk_index, chunk_text, metadata_json, embedding, embedding_dim FROM documents"
            )
            scored = []
            for (doc_id, source_path, chunk_index, chunk_text, metadata_json, emb_blob, emb_dim) in cur:
                v = self._unpack_embedding(emb_blob, emb_dim)
                vn = np.linalg.norm(v) + 1e-12
                score = float(np.dot(q, v) / (qn * vn))
                scored.append(
                    {
                        "id": doc_id,
                        "source_path": source_path,
                        "chunk_index": int(chunk_index),
                        "chunk_text": chunk_text,
                        "metadata": json.loads(metadata_json) if metadata_json else {},
                        "score": score,
                    }
                )
            scored.sort(key=lambda x: x["score"], reverse=True)
            return scored[: max(1, int(top_k))]
        finally:
            conn.close()


@dataclass
class RetrievedDoc:
    id: str
    source_path: str
    chunk_index: int
    score: float
    text: str
    metadata: Dict[str, Any]


class RAGSystem:
    def __init__(
        self,
        db_path: str = DEFAULT_DB_PATH,
        docs_dir: str = DEFAULT_DOCS_DIR,
        embed_model: str = DEFAULT_EMBED_MODEL,
        chat_model: str = DEFAULT_CHAT_MODEL,
        top_k: int = DEFAULT_TOP_K,
        max_chunk_chars: int = DEFAULT_MAX_CHUNK_CHARS,
        chunk_overlap_chars: int = DEFAULT_CHUNK_OVERLAP_CHARS,
        max_context_chars: int = DEFAULT_MAX_CONTEXT_CHARS,
        openai_api_key: str = DEFAULT_OPENAI_API_KEY,
        openai_base_url: str = DEFAULT_OPENAI_BASE_URL,
    ):
        self.db = VectorStoreSQLite(db_path)
        self.docs_dir = docs_dir
        self.embed_model = embed_model
        self.chat_model = chat_model
        self.top_k = top_k
        self.max_chunk_chars = max_chunk_chars
        self.chunk_overlap_chars = chunk_overlap_chars
        self.max_context_chars = max_context_chars
        self.client = OpenAIClient(api_key=openai_api_key, base_url=openai_base_url)

    def _file_sha(self, path: str) -> str:
        data = _read_text_file(path)
        return _sha256_hex(data)

    def index_documents(self, docs_dir: Optional[str] = None, force: bool = False, batch_size: int = 64) -> Dict[str, Any]:
        docs_dir = docs_dir or self.docs_dir
        files = _iter_files(docs_dir)
        indexed_files = 0
        indexed_chunks = 0
        skipped_files = 0
        errors = []

        for path in files:
            try:
                mtime = int(os.path.getmtime(path))
                sha = self._file_sha(path)
                existing_sha = self.db.get_source_sha(path)
                if (not force) and existing_sha == sha:
                    skipped_files += 1
                    continue

                text = _read_text_file(path)
                chunks = chunk_text(text, self.max_chunk_chars, self.chunk_overlap_chars)
                if not chunks:
                    skipped_files += 1
                    continue

                embeddings = []
                for i in range(0, len(chunks), batch_size):
                    batch = chunks[i : i + batch_size]
                    embeddings.extend(self.client.embeddings(self.embed_model, batch))

                metadatas = []
                for i, ch in enumerate(chunks):
                    metadatas.append(
                        {
                            "filename": os.path.basename(path),
                            "relative_path": os.path.relpath(path, docs_dir),
                            "chunk_chars": len(ch),
                        }
                    )

                n = self.db.upsert_chunks(path, mtime, sha, chunks, embeddings, metadatas)
                indexed_files += 1
                indexed_chunks += n
            except Exception as e:
                errors.append({"path": path, "error": str(e)})
        return {
            "docs_dir": docs_dir,
            "files_found": len(files),
            "files_indexed": indexed_files,
            "chunks_indexed": indexed_chunks,
            "files_skipped": skipped_files,
            "errors": errors,
        }

    def retrieve(self, query: str, top_k: Optional[int] = None) -> List[RetrievedDoc]:
        top_k = int(top_k or self.top_k)
        q_emb = self.client.embeddings(self.embed_model, [query])[0]
        hits = self.db.search(q_emb, top_k=top_k)
        out = []
        for h in hits:
            out.append(
                RetrievedDoc(
                    id=h["id"],
                    source_path=h["source_path"],
                    chunk_index=h["chunk_index"],
                    score=h["score"],
                    text=h["chunk_text"],
                    metadata=h.get("metadata") or {},
                )
            )
        return out

    def _build_prompt(self, query: str, retrieved: List[RetrievedDoc]) -> List[Dict[str, str]]:
        context_parts = []
        total = 0
        for i, d in enumerate(retrieved, start=1):
            header = f"[DOC {i}] source={d.source_path} chunk={d.chunk_index} score={d.score:.4f}"
            body = d.text
            part = header + "\n" + body
            if total + len(part) + 2 > self.max_context_chars:
                break
            context_parts.append(part)
            total += len(part) + 2

        context = "\n\n---\n\n".join(context_parts) if context_parts else "(no relevant documents retrieved)"

        system = (
            "You are an internal knowledge base assistant for company employees.\n"
            "Use ONLY the provided retrieved documents as your source of truth.\n"
            "If the answer is not contained in the documents, say you don't know and ask a clarifying question.\n"
            "Cite sources by referencing DOC numbers like [DOC 1], [DOC 2].\n"
            "Be concise and accurate."
        )

        user = (
            "User question:\n"
            f"{query}\n\n"
            "Retrieved documents (use all of them):\n"
            f"{context}"
        )

        return [{"role": "system", "content": system}, {"role": "user", "content": user}]

    def answer(self, query: str, top_k: Optional[int] = None, temperature: float = 0.2) -> Dict[str, Any]:
        retrieved = self.retrieve(query, top_k=top_k)
        messages = self._build_prompt(query, retrieved)
        response = self.client.chat(self.chat_model, messages, temperature=temperature)
        return {
            "query": query,
            "answer": response,
            "retrieved": [
                {
                    "id": d.id,
                    "source_path": d.source_path,
                    "chunk_index": d.chunk_index,
                    "score": d.score,
                    "metadata": d.metadata,
                    "text": d.text,
                }
                for d in retrieved
            ],
        }


def _cmd_index(args: argparse.Namespace) -> int:
    rag = RAGSystem(
        db_path=args.db,
        docs_dir=args.docs,
        embed_model=args.embed_model,
        chat_model=args.chat_model,
        top_k=args.top_k,
        max_chunk_chars=args.max_chunk_chars,
        chunk_overlap_chars=args.chunk_overlap_chars,
        max_context_chars=args.max_context_chars,
        openai_api_key=args.openai_api_key or DEFAULT_OPENAI_API_KEY,
        openai_base_url=args.openai_base_url or DEFAULT_OPENAI_BASE_URL,
    )
    res = rag.index_documents(force=args.force)
    print(json.dumps(res, indent=2, ensure_ascii=False))
    return 0 if not res["errors"] else 2


def _cmd_chat(args: argparse.Namespace) -> int:
    rag = RAGSystem(
        db_path=args.db,
        docs_dir=args.docs,
        embed_model=args.embed_model,
        chat_model=args.chat_model,
        top_k=args.top_k,
        max_chunk_chars=args.max_chunk_chars,
        chunk_overlap_chars=args.chunk_overlap_chars,
        max_context_chars=args.max_context_chars,
        openai_api_key=args.openai_api_key or DEFAULT_OPENAI_API_KEY,
        openai_base_url=args.openai_base_url or DEFAULT_OPENAI_BASE_URL,
    )

    if args.query:
        out = rag.answer(args.query, top_k=args.top_k, temperature=args.temperature)
        if args.json:
            print(json.dumps(out, indent=2, ensure_ascii=False))
        else:
            print(out["answer"])
        return 0

    print("RAG chat. Type your question and press Enter. Type /exit to quit. Type /reindex to re-index docs.")
    while True:
        try:
            q = input("\n> ").strip()
        except (EOFError, KeyboardInterrupt):
            print()
            break
        if not q:
            continue
        if q.lower() in ("/exit", "exit", "quit", "/quit"):
            break
        if q.lower() in ("/reindex", "reindex", "/index"):
            res = rag.index_documents(force=False)
            print(json.dumps(res, indent=2, ensure_ascii=False))
            continue
        out = rag.answer(q, top_k=args.top_k, temperature=args.temperature)
        if args.json:
            print(json.dumps(out, indent=2, ensure_ascii=False))
        else:
            print(out["answer"])
    return 0


def _cmd_retrieve(args: argparse.Namespace) -> int:
    rag = RAGSystem(
        db_path=args.db,
        docs_dir=args.docs,
        embed_model=args.embed_model,
        chat_model=args.chat_model,
        top_k=args.top_k,
        max_chunk_chars=args.max_chunk_chars,
        chunk_overlap_chars=args.chunk_overlap_chars,
        max_context_chars=args.max_context_chars,
        openai_api_key=args.openai_api_key or DEFAULT_OPENAI_API_KEY,
        openai_base_url=args.openai_base_url or DEFAULT_OPENAI_BASE_URL,
    )
    hits = rag.retrieve(args.query, top_k=args.top_k)
    out = [
        {
            "id": d.id,
            "source_path": d.source_path,
            "chunk_index": d.chunk_index,
            "score": d.score,
            "metadata": d.metadata,
            "text": d.text,
        }
        for d in hits
    ]
    print(json.dumps({"query": args.query, "top_k": args.top_k, "results": out}, indent=2, ensure_ascii=False))
    return 0


def build_arg_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(description="Simple Python RAG system (SQLite vector store + OpenAI embeddings/chat).")
    p.add_argument("--db", default=DEFAULT_DB_PATH, help=f"SQLite DB path (default: {DEFAULT_DB_PATH})")
    p.add_argument("--docs", default=DEFAULT_DOCS_DIR, help=f"Documents directory (default: {DEFAULT_DOCS_DIR})")
    p.add_argument("--embed-model", default=DEFAULT_EMBED_MODEL, help=f"Embedding model (default: {DEFAULT_EMBED_MODEL})")
    p.add_argument("--chat-model", default=DEFAULT_CHAT_MODEL, help=f"Chat model (default: {DEFAULT_CHAT_MODEL})")
    p.add_argument("--top-k", type=int, default=DEFAULT_TOP_K, help=f"Top K retrieved chunks (default: {DEFAULT_TOP_K})")
    p.add_argument("--max-chunk-chars", type=int, default=DEFAULT_MAX_CHUNK_CHARS)
    p.add_argument("--chunk-overlap-chars", type=int, default=DEFAULT_CHUNK_OVERLAP_CHARS)
    p.add_argument("--max-context-chars", type=int, default=DEFAULT_MAX_CONTEXT_CHARS)
    p.add_argument("--openai-api-key", default=os.environ.get("OPENAI_API_KEY", ""), help="OpenAI API key (or set env OPENAI_API_KEY)")
    p.add_argument("--openai-base-url", default=os.environ.get("OPENAI_BASE_URL", DEFAULT_OPENAI_BASE_URL), help="OpenAI base URL")
    sub = p.add_subparsers(dest="cmd", required=True)

    p_index = sub.add_parser("index", help="Index documents into the vector store")
    p_index.add_argument("--force", action="store_true", help="Force re-index all files")
    p_index.set_defaults(func=_cmd_index)

    p_retrieve = sub.add_parser("retrieve", help="Retrieve relevant chunks for a query (no LLM call)")
    p_retrieve.add_argument("query", help="Query text")
    p_retrieve.set_defaults(func=_cmd_retrieve)

    p_chat = sub.add_parser("chat", help="Ask questions (retrieval + LLM). If --query omitted, starts interactive chat.")
    p_chat.add_argument("--query", default="", help="Single query (non-interactive)")
    p_chat.add_argument("--temperature", type=float, default=0.2)
    p_chat.add_argument("--json", action="store_true", help="Output full JSON including retrieved docs")
    p_chat.set_defaults(func=_cmd_chat)

    return p


def main(argv: Optional[List[str]] = None) -> int:
    parser = build_arg_parser()
    args = parser.parse_args(argv)
    return args.func(args)


if __name__ == "__main__":
    raise SystemExit(main())